--- a/staging/src/k8s.io/client-go/tools/cache/delta_fifo.go
+++ b/staging/src/k8s.io/client-go/tools/cache/delta_fifo.go
@@ -418,6 +418,12 @@ func (f *DeltaFIFO) Replace(list []interface{}, resourceVersion string) error {
 		for k := range f.items {
 			if _, exists := keys[k]; !exists {
 				if err := f.deleteDeltaLocked(k, DeletedFinalStateUnknown{...}); err != nil { ... }
 			}
 		}
+		// Skip syncKeyLocked for keys that already have a pending Sync/Replaced delta
+		// to avoid emitting duplicate Update events when resync and re-list race.
 		for k := range keys {
+			if f.hasPendingSyncDelta(k) {
+				continue
+			}
 			if err := f.syncKeyLocked(k); err != nil { ... }
 		}
 }
+
+func (f *DeltaFIFO) hasPendingSyncDelta(key string) bool {
+	deltas := f.items[key]
+	for _, d := range deltas {
+		if d.Type == Sync || d.Type == Replaced {
+			return true
+		}
+	}
+	return false
+}
